# aws
locals {
  current_account_id                     = data.aws_caller_identity.current.account_id # tflint-ignore: terraform_unused_declarations
  current_account_name                   = var.aws_account_name
  current_region                         = data.aws_region.current.id
  config_bucket_name                     = local.current_account_name != null ? "${local.current_account_name}-openclaw-config" : null
  aws_iam_role_management_delegation_arn = "arn:aws:iam::${var.aws_management_account_id}:role/${var.aws_iam_role_management_delegation_name}"
}

# bitwarden secret resolution
locals {
  bw_secret_keys_needed = distinct(compact(concat(
    ["TWINGATE_API_TOKEN", "TWINGATE_NETWORK"],
    [for instance in local.instances : instance.bitwarden_secret_key_ssh_public_key],
    [for instance in local.instances : instance.bitwarden_secret_key_openrouter_api_key],
    [for instance in local.instances : instance.bitwarden_secret_key_telegram_bot_token],
    [for instance in local.instances : instance.bitwarden_secret_key_discord_bot_token],
    [for instance in local.instances : instance.bitwarden_secret_key_approvals_password],
    [for instance in local.instances : instance.bitwarden_secret_key_google_workspace_token_key],
    [for instance in local.instances : instance.bitwarden_secret_key_google_client_id],
    [for instance in local.instances : instance.bitwarden_secret_key_google_client_secret],
  )))
  bw_secret_values = { for key, secret in data.bitwarden-secrets_secret.this : key => secret.value }
  bw_secrets       = { for s in data.bitwarden-secrets_list_secrets.all.secrets : s.key => s.id }
}

# twingate
locals {
  twingate_api_token = local.bw_secret_values["TWINGATE_API_TOKEN"]
  twingate_network   = local.bw_secret_values["TWINGATE_NETWORK"]
}

# instances
locals {
  instances = flatten([
    for instance_key, instance in var.instances : {
      instance_key                                    = instance_key
      name                                            = instance.name
      aws_ec2_instance_type                           = contains(keys(instance), "aws_ec2_instance_type") ? instance.aws_ec2_instance_type : "t4g.small"
      llm_models                                      = contains(keys(instance), "llm_models") ? instance.llm_models : { "openrouter/nvidia/nemotron-3-super-120b-a12b:free" = { primary = true } }
      aws_route53_zone_domain                         = instance.aws_route53_zone_domain
      aws_route53_zone_parent_domain                  = instance.aws_route53_zone_parent_domain
      twingate_group_ids                              = contains(keys(instance), "twingate_group_ids") ? instance.twingate_group_ids : null
      twingate_security_policy_name                   = instance.twingate_security_policy_name
      twingate_service_account_name                   = contains(keys(instance), "twingate_service_account_name") ? instance.twingate_service_account_name : null
      ec2_nightly_power_cycle_enabled                 = contains(keys(instance), "ec2_nightly_power_cycle_enabled") ? instance.ec2_nightly_power_cycle_enabled : false
      aws_ssm_maintenance_window_scan_schedule        = contains(keys(instance), "aws_ssm_maintenance_window_scan_schedule") ? instance.aws_ssm_maintenance_window_scan_schedule : "cron(0 8 ? * SAT *)"
      aws_ssm_maintenance_window_install_schedule     = contains(keys(instance), "aws_ssm_maintenance_window_install_schedule") ? instance.aws_ssm_maintenance_window_install_schedule : "cron(0 10 ? * SAT *)"
      aws_ssm_maintenance_window_timezone             = contains(keys(instance), "aws_ssm_maintenance_window_timezone") ? instance.aws_ssm_maintenance_window_timezone : "Europe/London"
      ha_ec2_sleep_control_enabled                    = contains(keys(instance), "ha_ec2_sleep_control_enabled") ? instance.ha_ec2_sleep_control_enabled : false
      ha_ec2_sleep_control_ddns_hostname              = contains(keys(instance), "ha_ec2_sleep_control_ddns_hostname") ? instance.ha_ec2_sleep_control_ddns_hostname : null
      bitwarden_secret_key_ssh_public_key             = instance.bitwarden_secret_key_ssh_public_key
      bitwarden_secret_key_openrouter_api_key         = contains(keys(instance), "bitwarden_secret_key_openrouter_api_key") ? instance.bitwarden_secret_key_openrouter_api_key : null
      bitwarden_secret_key_telegram_bot_token         = contains(keys(instance), "bitwarden_secret_key_telegram_bot_token") ? instance.bitwarden_secret_key_telegram_bot_token : null
      bitwarden_secret_key_discord_bot_token          = contains(keys(instance), "bitwarden_secret_key_discord_bot_token") ? instance.bitwarden_secret_key_discord_bot_token : null
      openclaw_tools_profile                          = contains(keys(instance), "openclaw_tools_profile") ? instance.openclaw_tools_profile : "coding"
      disabled_skills                                 = contains(keys(instance), "disabled_skills") ? instance.disabled_skills : []
      status_page_enabled                             = contains(keys(instance), "status_page_enabled") ? instance.status_page_enabled : false
      status_page_domain                              = contains(keys(instance), "status_page_domain") ? instance.status_page_domain : null
      telegram_allowed_sender_ids                     = contains(keys(instance), "telegram_allowed_sender_ids") ? instance.telegram_allowed_sender_ids : []
      discord_allowed_sender_ids                      = contains(keys(instance), "discord_allowed_sender_ids") ? instance.discord_allowed_sender_ids : []
      discord_guild_id                                = contains(keys(instance), "discord_guild_id") ? instance.discord_guild_id : null
      discord_guild_require_mention                   = contains(keys(instance), "discord_guild_require_mention") ? instance.discord_guild_require_mention : false
      bitwarden_secret_key_approvals_password         = contains(keys(instance), "bitwarden_secret_key_approvals_password") ? instance.bitwarden_secret_key_approvals_password : null
      bitwarden_secret_key_google_workspace_token_key = contains(keys(instance), "bitwarden_secret_key_google_workspace_token_key") ? instance.bitwarden_secret_key_google_workspace_token_key : null
      bitwarden_secret_key_google_client_id           = contains(keys(instance), "bitwarden_secret_key_google_client_id") ? instance.bitwarden_secret_key_google_client_id : null
      bitwarden_secret_key_google_client_secret       = contains(keys(instance), "bitwarden_secret_key_google_client_secret") ? instance.bitwarden_secret_key_google_client_secret : null
    }
  ])
}

# rendered openclaw.json per instance
locals {

  openclaw_base_config = jsondecode(file("${path.root}/../config/openclaw.json"))

  llm_primary_model = {
    for instance in local.instances : "${local.current_region}.${instance.name}" =>
    one([for k, v in instance.llm_models : k if try(v.primary, false)])
  }

  rendered_openclaw_config = {
    for instance in local.instances : "${local.current_region}.${instance.name}" => jsonencode(merge(
      local.openclaw_base_config,
      {
        agents = merge(
          lookup(local.openclaw_base_config, "agents", {}),
          {
            defaults = merge(
              lookup(lookup(local.openclaw_base_config, "agents", {}), "defaults", {}),
              {
                model = { primary = local.llm_primary_model["${local.current_region}.${instance.name}"] }
                models = merge(
                  { for k, v in instance.llm_models : k => {} },
                  { "openrouter/nvidia/nemotron-3-super-120b-a12b:free" = {} }
                )
              }
            )
          }
        )
        channels = merge(
          {
            telegram = {
              enabled  = instance.bitwarden_secret_key_telegram_bot_token != null
              dmPolicy = "pairing"
            }
          },
          {
            discord = merge(
              {
                enabled  = instance.bitwarden_secret_key_discord_bot_token != null
                dmPolicy = "pairing"
                token = {
                  source   = "env"
                  provider = "default"
                  id       = "DISCORD_BOT_TOKEN"
                }
                groupPolicy = "allowlist"
              },
              instance.discord_guild_id != null ? {
                guilds = {
                  (instance.discord_guild_id) = {
                    requireMention = instance.discord_guild_require_mention
                  }
                }
              } : {}
            )
          }
        )
        tools = {
          profile = instance.openclaw_tools_profile
        }
        skills = length(instance.disabled_skills) > 0 ? {
          entries = { for skill in instance.disabled_skills : skill => { enabled = false } }
        } : {}
      }
    ))
  }
}

# rendered model guide per instance
locals {

  rendered_model_guide = {
    for instance in local.instances : "${local.current_region}.${instance.name}" => join("\n", concat(
      [
        "# Model Guide",
        "",
        "Use this reference when choosing which model to use for a task.",
        "",
        "| Model | Primary | Description |",
        "| ----- | ------- | ----------- |",
      ],
      [
        for k, v in instance.llm_models :
        "| `${k}` | ${try(v.primary, false) ? "yes" : "no"} | ${try(v.description, "")} |"
      ],
      [
        "| `openrouter/nvidia/nemotron-3-super-120b-a12b:free` | no | Free tier. Use for high-token tasks (large context, lengthy generation, bulk processing) to conserve budget |",
        "",
        "When no specific model is requested, use the primary model.",
      ]
    ))
  }
}

# rendered cloudwatch agent config per instance
locals {

  rendered_cloudwatch_agent_config = {
    for instance in local.instances : "${local.current_region}.${instance.name}" => jsonencode({
      agent = {
        metrics_collection_interval = 60
        run_as_user                 = "root"
      }
      metrics = {
        namespace = "CWAgent"
        metrics_collected = {
          mem = {
            measurement                 = ["mem_used_percent"]
            metrics_collection_interval = 60
          }
          disk = {
            measurement                 = ["disk_used_percent"]
            metrics_collection_interval = 60
            resources                   = ["/home/openclaw"]
            drop_device                 = true
          }
        }
        append_dimensions = {
          InstanceId = "$${aws:InstanceId}"
        }
      }
    })
  }
}

resource "aws_ssm_parameter" "llm_api_key" {

  count = var.llm_api_key != null ? 1 : 0

  name  = "/${var.name}/llm-api-key"
  type  = "SecureString"
  value = var.llm_api_key
}

resource "aws_ssm_parameter" "telegram_bot_token" {

  count = var.telegram_bot_token != null ? 1 : 0

  name  = "/${var.name}/telegram-bot-token"
  type  = "SecureString"
  value = var.telegram_bot_token
}

resource "aws_ssm_parameter" "discord_bot_token" {

  count = var.discord_bot_token != null ? 1 : 0

  name  = "/${var.name}/discord-bot-token"
  type  = "SecureString"
  value = var.discord_bot_token
}

resource "aws_ssm_parameter" "approvals_password" {

  count = var.approvals_password != null ? 1 : 0

  name  = "/${var.name}/approvals-password"
  type  = "SecureString"
  value = var.approvals_password
}

resource "aws_ssm_parameter" "google_workspace_token_key" {

  count = var.google_workspace_token_key != null ? 1 : 0

  name  = "/${var.name}/google-workspace-token-key"
  type  = "SecureString"
  value = var.google_workspace_token_key
}

resource "aws_ssm_parameter" "google_client_id" {

  count = var.google_client_id != null ? 1 : 0

  name  = "/${var.name}/google-client-id"
  type  = "SecureString"
  value = var.google_client_id
}

resource "aws_ssm_parameter" "google_client_secret" {

  count = var.google_client_secret != null ? 1 : 0

  name  = "/${var.name}/google-client-secret"
  type  = "SecureString"
  value = var.google_client_secret
}

resource "random_password" "gateway_token" {

  length  = 64
  special = false
}

resource "aws_ssm_parameter" "gateway_token" {

  name  = "/${var.name}/gateway-token"
  type  = "SecureString"
  value = random_password.gateway_token.result
}

