		client, ctx := gmailClient()
		messages, err := client.SearchMessages(ctx, gmailSearchQuery, gmailSearchMaxResults)
		if err != nil {
			exitf("%v", err)
		}

		if outputFmt == "json" {
			printJSON(messages)
			return
		}

		for _, msg := range messages {
			fmt.Printf("ID: %s  ThreadID: %s\n", msg.Id, msg.ThreadId)
		}
	},
}

