)

var gmailThreadsCmd = &cobra.Command{
	Use:   "threads",
	Short: "List or read Gmail threads",
	Run: func(cmd *cobra.Command, args []string) {
		client, ctx := gmailClient()

		if gmailThreadsID != "" {
			thread, err := client.GetThread(ctx, gmailThreadsID)
			if err != nil {
				exitf("%v", err)
			}
			printJSON(thread)
